            } else {
                ret = (Double.doubleToRawLongBits(real) == Double.doubleToRawLongBits(rhs.getReal())) && (Double.doubleToRawLongBits(imaginary) == Double.doubleToRawLongBits(rhs.getImaginary())) || (imaginary == rhs.getImaginary() && !Double.isNaN(rhs.getImaginary()));
            }
